-- Now copy MTOW from modelo to registos that don't have it
UPDATE registo_aeronave ra SET mtow_kg = ma.mtow_kg
FROM modelo_aeronave ma
WHERE ra.id_modelo_aeronave = ma.id
  AND ma.mtow_kg > 0
  AND (ra.mtow_kg IS NULL OR ra.mtow_kg = 0);
